istener.\n     * @remarks If the same callback was subscribed more than once **all** occurences will be removed.\n     * @param event - Event name.\n     * @param callback - Callback method.\n     */\n    off(event, callback) {\n        this._subscribers[event] = this._subscribers[event].filter((subscriber) => subscriber !== callback);\n    }\n    /**\n     * @deprecated Use on instead (PS: DataView.subscribe === DataView.on).\n     */\n    subscribe = DataSetPart.prototype.on;\n    /**\n     * @deprecated Use off instead (PS: DataView.unsubscribe === DataView.off).\n     */\n    unsubscribe = DataSetPart.prototype.off;\n}\n\n/**\n * Data stream\n * @remarks\n * {@link DataStream} offers an always up to date stream of items from a {@link DataSet} or {@link DataView}.\n * That means that the stream is evaluated at the time of iteration, conversion to another data type or when {@link cache} is called, not when the {@link DataStream} was created.\n * Multiple invocations of for example {@link toItemArray} may yield different results (if the data source like for example {@link DataSet} gets modified).\n * @typeParam Item - The item type this stream is going to work with.\n */\nclass DataStream {\n    _pairs;\n    /**\n     * Create a new data stream.\n     * @param pairs - The id, item pairs.\n     */\n    constructor(pairs) {\n        this._pairs = pairs;\n    }\n    /**\n     * Return an iterable of key, value pairs for every entry in the stream.\n     */\n    *[Symbol.iterator]() {\n        for (const [id, item] of this._pairs) {\n            yield [id, item];\n        }\n    }\n    /**\n     * Return an iterable of key, value pairs for every entry in the stream.\n     */\n    *entries() {\n        for (const [id, item] of this._pairs) {\n            yield [id, item];\n        }\n    }\n    /**\n     * Return an iterable of keys in the stream.\n     */\n    *keys() {\n        for (const [id] of this._pairs) {\n            yield id;\n        }\n    }\n    /**\n     * Return an iterable of values in the stream.\n     */\n    *values() {\n        for (const [, item] of this._pairs) {\n            yield item;\n        }\n    }\n    /**\n     * Return an array containing all the ids in this stream.\n     * @remarks\n     * The array may contain duplicities.\n     * @returns The array with all ids from this stream.\n     */\n    toIdArray() {\n        return [...this._pairs].map((pair) => pair[0]);\n    }\n    /**\n     * Return an array containing all the items in this stream.\n     * @remarks\n     * The array may contain duplicities.\n     * @returns The array with all items from this stream.\n     */\n    toItemArray() {\n        return [...this._pairs].map((pair) => pair[1]);\n    }\n    /**\n     * Return an array containing all the entries in this stream.\n     * @remarks\n     * The array may contain duplicities.\n     * @returns The array with all entries from this stream.\n     */\n    toEntryArray() {\n        return [...this._pairs];\n    }\n    /**\n     * Return an object map containing all the items in this stream accessible by ids.\n     * @remarks\n     * In case of duplicate ids (coerced to string so `7 == '7'`) the last encoutered appears in the returned object.\n     * @returns The object map of all id → item pairs from this stream.\n     */\n    toObjectMap() {\n        const map = Object.create(null);\n        for (const [id, item] of this._pairs) {\n            map[id] = item;\n        }\n        return map;\n    }\n    /**\n     * Return a map containing all the items in this stream accessible by ids.\n     * @returns The map of all id → item pairs from this stream.\n     */\n    toMap() {\n        return new Map(this._pairs);\n    }\n    /**\n     * Return a set containing all the (unique) ids in this stream.\n     * @returns The set of all ids from this stream.\n     */\n    toIdSet() {\n        return new Set(this.toIdArray());\n    }\n    /**\n     * Return a set containing all the (unique) items in this stream.\n     * @returns The set of all items from this stream.\n     */\n    toItemSet() {\n        return new Set(this.toItemArray());\n    }\n    /**\n     * Cache the items from this stream.\n     * @remarks\n     * This method allows for items to be fetched immediatelly and used (possibly multiple times) later.\n     * It can also be used to optimize performance as {@link DataStream} would otherwise reevaluate everything upon each iteration.\n     *\n     * ## Example\n     * ```javascript\n     * const ds = new DataSet([…])\n     *\n     * const cachedStream = ds.stream()\n     *   .filter(…)\n     *   .sort(…)\n     *   .map(…)\n     *   .cached(…) // Data are fetched, processed and cached here.\n     *\n     * ds.clear()\n     * chachedStream // Still has all the items.\n     * ```\n     * @returns A new {@link DataStream} with cached items (detached from the original {@link DataSet}).\n     */\n    cache() {\n        return new DataStream([...this._pairs]);\n    }\n    /**\n     * Get the distinct values of given property.\n     * @param callback - The function that picks and possibly converts the property.\n     * @typeParam T - The type of the distinct value.\n     * @returns A set of all distinct properties.\n     */\n    distinct(callback) {\n        const set = new Set();\n        for (const [id, item] of this._pairs) {\n            set.add(callback(item, id));\n        }\n        return set;\n    }\n    /**\n     * Filter the items of the stream.\n     * @param callback - The function that decides whether an item will be included.\n     * @returns A new data stream with the filtered items.\n     */\n    filter(callback) {\n        const pairs = this._pairs;\n        return new DataStream({\n            *[Symbol.iterator]() {\n                for (const [id, item] of pairs) {\n                    if (callback(item, id)) {\n                        yield [id, item];\n                    }\n                }\n            },\n        });\n    }\n    /**\n     * Execute a callback for each item of the stream.\n     * @param callback - The function that will be invoked for each item.\n     */\n    forEach(callback) {\n        for (const [id, item] of this._pairs) {\n            callback(item, id);\n        }\n    }\n    /**\n     * Map the items into a different type.\n     * @param callback - The function that does the conversion.\n     * @typeParam Mapped - The type of the item after mapping.\n     * @returns A new data stream with the mapped items.\n     */\n    map(callback) {\n        const pairs = this._pairs;\n        return new DataStream({\n            *[Symbol.iterator]() {\n                for (const [id, item] of pairs) {\n                    yield [id, callback(item, id)];\n                }\n            },\n        });\n    }\n    /**\n     * Get the item with the maximum value of given property.\n     * @param callback - The function that picks and possibly converts the property.\n     * @returns The item with the maximum if found otherwise null.\n     */\n    max(callback) {\n        const iter = this._pairs[Symbol.iterator]();\n        let curr = iter.next();\n        if (curr.done) {\n            return null;\n        }\n        let maxItem = curr.value[1];\n        let maxValue = callback(curr.value[1], curr.value[0]);\n        while (!(curr = iter.next()).done) {\n            const [id, item] = curr.value;\n            const value = callback(item, id);\n            if (value > maxValue) {\n                maxValue = value;\n                maxItem = item;\n            }\n        }\n        return maxItem;\n    }\n    /**\n     * Get the item with the minimum value of given property.\n     * @param callback - The function that picks and possibly converts the property.\n     * @returns The item with the minimum if found otherwise null.\n     */\n    min(callback) {\n        const iter = this._pairs[Symbol.iterator]();\n        let curr = iter.next();\n        if (curr.done) {\n            return null;\n        }\n        let minItem = curr.value[1];\n        let minValue = callback(curr.value[1], curr.value[0]);\n        while (!(curr = iter.next()).done) {\n            const [id, item] = curr.value;\n            const value = callback(item, id);\n            if (value < minValue) {\n                minValue = value;\n                minItem = item;\n            }\n        }\n        return minItem;\n    }\n    /**\n     * Reduce the items into a single value.\n     * @param callback - The function that does the reduction.\n     * @param accumulator - The initial value of the accumulator.\n     * @typeParam T - The type of the accumulated value.\n     * @returns The reduced value.\n     */\n    reduce(callback, accumulator) {\n        for (const [id, item] of this._pairs) {\n            accumulator = callback(accumulator, item, id);\n        }\n        return accumulator;\n    }\n    /**\n     * Sort the items.\n     * @param callback - Item comparator.\n     * @returns A new stream with sorted items.\n     */\n    sort(callback) {\n        return new DataStream({\n            [Symbol.iterator]: () => [...this._pairs]\n                .sort(([idA, itemA], [idB, itemB]) => callback(itemA, itemB, idA, idB))[Symbol.iterator](),\n        });\n    }\n}\n\n/**\n * Add an id to given item if it doesn't have one already.\n * @remarks\n * The item will be modified.\n * @param item - The item that will have an id after a call to this function.\n * @param idProp - The key of the id property.\n * @typeParam Item - Item type that may or may not have an id.\n * @typeParam IdProp - Name of the property that contains the id.\n * @returns true\n */\nfunction ensureFullItem(item, idProp) {\n    if (item[idProp] == null) {\n        // generate an id\n        item[idProp] = v4();\n    }\n    return item;\n}\n/**\n * # DataSet\n *\n * Vis.js comes with a flexible DataSet, which can be used to hold and\n * manipulate unstructured data and listen for changes in the data. The DataSet\n * is key/value based. Data items can be added, updated and removed from the\n * DataSet, and one can subscribe to changes in the DataSet. The data in the\n * DataSet can be filtered and ordered. Data can be normalized when appending it\n * to the DataSet as well.\n *\n * ## Example\n *\n * The following example shows how to use a DataSet.\n *\n * ```javascript\n * // create a DataSet\n * var options = {};\n * var data = new vis.DataSet(options);\n *\n * // add items\n * // note that the data items can contain different properties and data formats\n * data.add([\n * {id: 1, text: 'item 1', date: new Date(2013, 6, 20), group: 1, first: true},\n * {id: 2, text: 'item 2', date: '2013-06-23', group: 2},\n * {id: 3, text: 'item 3', date: '2013-06-25', group: 2},\n * {id: 4, text: 'item 4'}\n * ]);\n *\n * // subscribe to any change in the DataSet\n * data.on('*', function (event, properties, senderId) {\n * console.log('event', event, properties);\n * });\n *\n * // update an existing item\n * data.update({id: 2, group: 1});\n *\n * // remove an item\n * data.remove(4);\n *\n * // get all ids\n * var ids = data.getIds();\n * console.log('ids', ids);\n *\n * // get a specific item\n * var item1 = data.get(1);\n * console.log('item1', item1);\n *\n * // retrieve a filtered subset of the data\n * var items = data.get({\n * filter: function (item) {\n * return item.group == 1;\n * }\n * });\n * console.log('filtered items', items);\n * ```\n * @typeParam Item - Item type that may or may not have an id.\n * @typeParam IdProp - Name of the property that contains the id.\n */\nclass DataSet extends DataSetPart {\n    /** Flush all queued calls. */\n    flush;\n    /** @inheritDoc */\n    length;\n    /** @inheritDoc */\n    get idProp() {\n        return this._idProp;\n    }\n    _options;\n    _data;\n    _idProp;\n    _queue = null;\n    /**\n     * Construct a new DataSet.\n     * @param data - Initial data or options.\n     * @param options - Options (type error if data is also options).\n     */\n    constructor(data, options) {\n        super();\n        // correctly read optional arguments\n        if (data && !Array.isArray(data)) {\n            options = data;\n            data = [];\n        }\n        this._options = options || {};\n        this._data = new Map(); // map with data indexed by id\n        this.length = 0; // number of items in the DataSet\n        this._idProp = this._options.fieldId || \"id\"; // name of the field containing id\n        // add initial data when provided\n        if (data && data.length) {\n            this.add(data);\n        }\n        this.setOptions(options);\n    }\n    /**\n     * Set new options.\n     * @param options - The new options.\n     */\n    setOptions(options) {\n        if (options && options.queue !== undefined) {\n            if (options.queue === false) {\n                // delete queue if loaded\n                if (this._queue) {\n                    this._queue.destroy();\n                    this._queue = null;\n                }\n            }\n            else {\n                // create queue and update its options\n                if (!this._queue) {\n                    this._queue = Queue.extend(this, {\n                        replace: [\"add\", \"update\", \"remove\"],\n                    });\n                }\n                if (options.queue && typeof options.queue === \"object\") {\n                    this._queue.setOptions(options.queue);\n                }\n            }\n        }\n    }\n    /**\n     * Add a data item or an array with items.\n     *\n     * After the items are added to the DataSet, the DataSet will trigger an event `add`. When a `senderId` is provided, this id will be passed with the triggered event to all subscribers.\n     *\n     * ## Example\n     *\n     * ```javascript\n     * // create a DataSet\n     * const data = new vis.DataSet()\n     *\n     * // add items\n     * const ids = data.add([\n     * { id: 1, text: 'item 1' },\n     * { id: 2, text: 'item 2' },\n     * { text: 'item without an id' }\n     * ])\n     *\n     * console.log(ids) // [1, 2, '<UUIDv4>']\n     * ```\n     * @param data - Items to be added (ids will be generated if missing).\n     * @param senderId - Sender id.\n     * @returns addedIds - Array with the ids (generated if not present) of the added items.\n     * @throws When an item with the same id as any of the added items already exists.\n     */\n    add(data, senderId) {\n        const addedIds = [];\n        let id;\n        if (Array.isArray(data)) {\n            // Array\n            const idsToAdd = data.map((d) => d[this._idProp]);\n            if (idsToAdd.some((id) => this._data.has(id))) {\n                throw new Error(\"A duplicate id was found in the parameter array.\");\n            }\n            for (let i = 0, len = data.length; i < len; i++) {\n                id = this._addItem(data[i]);\n                addedIds.push(id);\n            }\n        }\n        else if (data && typeof data === \"object\") {\n            // Single item\n            id = this._addItem(data);\n            addedIds.push(id);\n        }\n        else {\n            throw new Error(\"Unknown dataType\");\n        }\n        if (addedIds.length) {\n            this._trigger(\"add\", { items: addedIds }, senderId);\n        }\n        return addedIds;\n    }\n    /**\n     * Update existing items. When an item does not exist, it will be created.\n     * @remarks\n     * The provided properties will be merged in the existing item. When an item does not exist, it will be created.\n     *\n     * After the items are updated, the DataSet will trigger an event `add` for the added items, and an event `update`. When a `senderId` is provided, this id will be passed with the triggered event to all subscribers.\n     *\n     * ## Example\n     *\n     * ```javascript\n     * // create a DataSet\n     * const data = new vis.DataSet([\n     *   { id: 1, text: 'item 1' },\n     *   { id: 2, text: 'item 2' },\n     *   { id: 3, text: 'item 3' }\n     * ])\n     *\n     * // update items\n     * const ids = data.update([\n     *   { id: 2, text: 'item 2 (updated)' },\n     *   { id: 4, text: 'item 4 (new)' }\n     * ])\n     *\n     * console.log(ids) // [2, 4]\n     * ```\n     *\n     * ## Warning for TypeScript users\n     * This method may introduce partial items into the data set. Use add or updateOnly instead for better type safety.\n     * @param data - Items to be updated (if the id is already present) or added (if the id is missing).\n     * @param senderId - Sender id.\n     * @returns updatedIds - The ids of the added (these may be newly generated if there was no id in the item from the data) or updated items.\n     * @throws When the supplied data is neither an item nor an array of items.\n     */\n    update(data, senderId) {\n        const addedIds = [];\n        const updatedIds = [];\n        const oldData = [];\n        const updatedData = [];\n        const idProp = this._idProp;\n        const addOrUpdate = (item) => {\n            const origId = item[idProp];\n            if (origId != null && this._data.has(origId)) {\n                const fullItem = item; // it has an id, therefore it is a fullitem\n                const oldItem = Object.assign({}, this._data.get(origId));\n                // update item\n                const id = this._updateItem(fullItem);\n                updatedIds.push(id);\n                updatedData.push(fullItem);\n                oldData.push(oldItem);\n            }\n            else {\n                // add new item\n                const id = this._addItem(item);\n                addedIds.push(id);\n            }\n        };\n        if (Array.isArray(data)) {\n            // Array\n            for (let i = 0, len = data.length; i < len; i++) {\n                if (data[i] && typeof data[i] === \"object\") {\n                    addOrUpdate(data[i]);\n                }\n                else {\n                    console.warn(\"Ignoring input item, which is not an object at index \" + i);\n                }\n            }\n        }\n        else if (data && typeof data === \"object\") {\n            // Single item\n            addOrUpdate(data);\n        }\n        else {\n            throw new Error(\"Unknown dataType\");\n        }\n        if (addedIds.length) {\n            this._trigger(\"add\", { items: addedIds }, senderId);\n        }\n        if (updatedIds.length) {\n            const props = { items: updatedIds, oldData: oldData, data: updatedData };\n            // TODO: remove deprecated property 'data' some day\n            //Object.defineProperty(props, 'data', {\n            //  'get': (function() {\n            //    console.warn('Property data is deprecated. Use DataSet.get(ids) to retrieve the new data, use the oldData property on this object to get the old data');\n            //    return updatedData;\n            //  }).bind(this)\n            //});\n            this._trigger(\"update\", props, senderId);\n        }\n        return addedIds.concat(updatedIds);\n    }\n    /**\n     * Update existing items. When an item does not exist, an error will be thrown.\n     * @remarks\n     * The provided properties will be deeply merged into the existing item.\n     * When an item does not exist (id not present in the data set or absent), an error will be thrown and nothing will be changed.\n     *\n     * After the items are updated, the DataSet will trigger an event `update`.\n     * When a `senderId` is provided, this id will be passed with the triggered event to all subscribers.\n     *\n     * ## Example\n     *\n     * ```javascript\n     * // create a DataSet\n     * const data = new vis.DataSet([\n     *   { id: 1, text: 'item 1' },\n     *   { id: 2, text: 'item 2' },\n     *   { id: 3, text: 'item 3' },\n     * ])\n     *\n     * // update items\n     * const ids = data.update([\n     *   { id: 2, text: 'item 2 (updated)' }, // works\n     *   // { id: 4, text: 'item 4 (new)' }, // would throw\n     *   // { text: 'item 4 (new)' }, // would also throw\n     * ])\n     *\n     * console.log(ids) // [2]\n     * ```\n     * @param data - Updates (the id and optionally other props) to the items in this data set.\n     * @param senderId - Sender id.\n     * @returns updatedIds - The ids of the updated items.\n     * @throws When the supplied data is neither an item nor an array of items, when the ids are missing.\n     */\n    updateOnly(data, senderId) {\n        if (!Array.isArray(data)) {\n            data = [data];\n        }\n        const updateEventData = data\n            .map((update) => {\n            const oldData = this._data.get(update[this._idProp]);\n            if (oldData == null) {\n                throw new Error(\"Updating non-existent items is not allowed.\");\n            }\n            return { oldData, update };\n        })\n            .map(({ oldData, update, }) => {\n            const id = oldData[this._idProp];\n            const updatedData = pureDeepObjectAssign(oldData, update);\n            this._data.set(id, updatedData);\n            return {\n                id,\n                oldData: oldData,\n                updatedData,\n            };\n        });\n        if (updateEventData.length) {\n            const props = {\n                items: updateEventData.map((value) => value.id),\n                oldData: updateEventData.map((value) => value.oldData),\n                data: updateEventData.map((value) => value.updatedData),\n            };\n            // TODO: remove deprecated property 'data' some day\n            //Object.defineProperty(props, 'data', {\n            //  'get': (function() {\n            //    console.warn('Property data is deprecated. Use DataSet.get(ids) to retrieve the new data, use the oldData property on this object to get the old data');\n            //    return updatedData;\n            //  }).bind(this)\n            //});\n            this._trigger(\"update\", props, senderId);\n            return props.items;\n        }\n        else {\n            return [];\n        }\n    }\n    /** @inheritDoc */\n    get(first, second) {\n        // @TODO: Woudn't it be better to split this into multiple methods?\n        // parse the arguments\n        let id = undefined;\n        let ids = undefined;\n        let options = undefined;\n        if (isId(first)) {\n            // get(id [, options])\n            id = first;\n            options = second;\n        }\n        else if (Array.isArray(first)) {\n            // get(ids [, options])\n            ids = first;\n            options = second;\n        }\n        else {\n            // get([, options])\n            options = first;\n        }\n        // determine the return type\n        const returnType = options && options.returnType === \"Object\" ? \"Object\" : \"Array\";\n        // @TODO: WTF is this? Or am I missing something?\n        // var returnType\n        // if (options && options.returnType) {\n        //   var allowedValues = ['Array', 'Object']\n        //   returnType =\n        //     allowedValues.indexOf(options.returnType) == -1\n        //       ? 'Array'\n        //       : options.returnType\n        // } else {\n        //   returnType = 'Array'\n        // }\n        // build options\n        const filter = options && options.filter;\n        const items = [];\n        let item = undefined;\n        let itemIds = undefined;\n        let itemId = undefined;\n        // convert items\n        if (id != null) {\n            // return a single item\n            item = this._data.get(id);\n            if (item && filter && !filter(item)) {\n                item = undefined;\n            }\n        }\n        else if (ids != null) {\n            // return a subset of items\n            for (let i = 0, len = ids.length; i < len; i++) {\n                item = this._data.get(ids[i]);\n                if (item != null && (!filter || filter(item))) {\n                    items.push(item);\n                }\n            }\n        }\n        else {\n            // return all items\n            itemIds = [...this._data.keys()];\n            for (let i = 0, len = itemIds.length; i < len; i++) {\n                itemId = itemIds[i];\n                item = this._data.get(itemId);\n                if (item != null && (!filter || filter(item))) {\n                    items.push(item);\n                }\n            }\n        }\n        // order the results\n        if (options && options.order && id == undefined) {\n            this._sort(items, options.order);\n        }\n        // filter fields of the items\n        if (options && options.fields) {\n            const fields = options.fields;\n            if (id != undefined && item != null) {\n                item = this._filterFields(item, fields);\n            }\n            else {\n                for (let i = 0, len = items.length; i < len; i++) {\n                    items[i] = this._filterFields(items[i], fields);\n                }\n            }\n        }\n        // return the results\n        if (returnType == \"Object\") {\n            const result = {};\n            for (let i = 0, len = items.length; i < len; i++) {\n                const resultant = items[i];\n                // @TODO: Shoudn't this be this._fieldId?\n                // result[resultant.id] = resultant\n                const id = resultant[this._idProp];\n                result[id] = resultant;\n            }\n            return result;\n        }\n        else {\n            if (id != null) {\n                // a single item\n                return item ?? null;\n            }\n            else {\n                // just return our array\n                return items;\n            }\n        }\n    }\n    /** @inheritDoc */\n    getIds(options) {\n        const data = this._data;\n        const filter = options && options.filter;\n        const order = options && options.order;\n        const itemIds = [...data.keys()];\n        const ids = [];\n        if (filter) {\n            // get filtered items\n            if (order) {\n                // create ordered list\n                const items = [];\n                for (let i = 0, len = itemIds.length; i < len; i++) {\n                    const id = itemIds[i];\n                    const item = this._data.get(id);\n                    if (item != null && filter(item)) {\n                        items.push(item);\n                    }\n                }\n                this._sort(items, order);\n                for (let i = 0, len = items.length; i < len; i++) {\n                    ids.push(items[i][this._idProp]);\n                }\n            }\n            else {\n                // create unordered list\n                for (let i = 0, len = itemIds.length; i < len; i++) {\n                    const id = itemIds[i];\n                    const item = this._data.get(id);\n                    if (item != null && filter(item)) {\n                        ids.push(item[this._idProp]);\n                    }\n                }\n            }\n        }\n        else {\n            // get all items\n            if (order) {\n                // create an ordered list\n                const items = [];\n                for (let i = 0, len = itemIds.length; i < len; i++) {\n                    const id = itemIds[i];\n                    items.push(data.get(id));\n                }\n                this._sort(items, order);\n                for (let i = 0, len = items.length; i < len; i++) {\n                    ids.push(items[i][this._idProp]);\n                }\n            }\n            else {\n                // create unordered list\n                for (let i = 0, len = itemIds.length; i < len; i++) {\n                    const id = itemIds[i];\n                    const item = data.get(id);\n                    if (item != null) {\n                        ids.push(item[this._idProp]);\n                    }\n                }\n            }\n        }\n        return ids;\n    }\n    /** @inheritDoc */\n    getDataSet() {\n        return this;\n    }\n    /** @inheritDoc */\n    forEach(callback, options) {\n        const filter = options && options.filter;\n        const data = this._data;\n        const itemIds = [...data.keys()];\n        if (options && options.order) {\n            // execute forEach on ordered list\n            const items = this.get(options);\n            for (let i = 0, len = items.length; i < len; i++) {\n                const item = items[i];\n                const id = item[this._idProp];\n                callback(item, id);\n            }\n        }\n        else {\n            // unordered\n            for (let i = 0, len = itemIds.length; i < len; i++) {\n                const id = itemIds[i];\n                const item = this._data.get(id);\n                if (item != null && (!filter || filter(item))) {\n                    callback(item, id);\n                }\n            }\n        }\n    }\n    /** @inheritDoc */\n    map(callback, options) {\n        const filter = options && options.filter;\n        const mappedItems = [];\n        const data = this._data;\n        const itemIds = [...data.keys()];\n        // convert and filter items\n        for (let i = 0, len = itemIds.length; i < len; i++) {\n            const id = itemIds[i];\n            const item = this._data.get(id);\n            if (item != null && (!filter || filter(item))) {\n                mappedItems.push(callback(item, id));\n            }\n        }\n        // order items\n        if (options && options.order) {\n            this._sort(mappedItems, options.order);\n        }\n        return mappedItems;\n    }\n    /**\n     * Filter the fields of an item.\n     * @param item - The item whose fields should be filtered.\n     * @param fields - The names of the fields that will be kept.\n     * @typeParam K - Field name type.\n     * @returns The item without any additional fields.\n     */\n    _filterFields(item, fields) {\n        if (!item) {\n            // item is null\n            return item;\n        }\n        return (Array.isArray(fields)\n            ? // Use the supplied array\n                fields\n            : // Use the keys of the supplied object\n                Object.keys(fields)).reduce((filteredItem, field) => {\n            filteredItem[field] = item[field];\n            return filteredItem;\n        }, {});\n    }\n    /**\n     * Sort the provided array with items.\n     * @param items - Items to be sorted in place.\n     * @param order - A field name or custom sort function.\n     * @typeParam T - The type of the items in the items array.\n     */\n    _sort(items, order) {\n        if (typeof order === \"string\") {\n            // order by provided field name\n            const name = order; // field name\n            items.sort((a, b) => {\n                // @TODO: How to treat missing properties?\n                const av = a[name];\n                const bv = b[name];\n                return av > bv ? 1 : av < bv ? -1 : 0;\n            });\n        }\n        else if (typeof order === \"function\") {\n            // order by sort function\n            items.sort(order);\n        }\n        else {\n            // TODO: extend order by an Object {field:string, direction:string}\n            //       where direction can be 'asc' or 'desc'\n            throw new TypeError(\"Order must be a function or a string\");\n        }\n    }\n    /**\n     * Remove an item or multiple items by “reference” (only the id is used) or by id.\n     *\n     * The method ignores removal of non-existing items, and returns an array containing the ids of the items which are actually removed from the DataSet.\n     *\n     * After the items are removed, the DataSet will trigger an event `remove` for the removed items. When a `senderId` is provided, this id will be passed with the triggered event to all subscribers.\n     *\n     * ## Example\n     * ```javascript\n     * // create a DataSet\n     * const data = new vis.DataSet([\n     * { id: 1, text: 'item 1' },\n     * { id: 2, text: 'item 2' },\n     * { id: 3, text: 'item 3' }\n     * ])\n     *\n     * // remove items\n     * const ids = data.remove([2, { id: 3 }, 4])\n     *\n     * console.log(ids) // [2, 3]\n     * ```\n     * @param id - One or more items or ids of items to be removed.\n     * @param senderId - Sender id.\n     * @returns The ids of the removed items.\n     */\n    remove(id, senderId) {\n        const removedIds = [];\n        const removedItems = [];\n        // force everything to be an array for simplicity\n        const ids = Array.isArray(id) ? id : [id];\n        for (let i = 0, len = ids.length; i < len; i++) {\n            const item = this._remove(ids[i]);\n            if (item) {\n                const itemId = item[this._idProp];\n                if (itemId != null) {\n                    removedIds.push(itemId);\n                    removedItems.push(item);\n                }\n            }\n        }\n        if (removedIds.length) {\n            this._trigger(\"remove\", { items: removedIds, oldData: removedItems }, senderId);\n        }\n        return removedIds;\n    }\n    /**\n     * Remove an item by its id or reference.\n     * @param id - Id of an item or the item itself.\n     * @returns The removed item if removed, null otherwise.\n     */\n    _remove(id) {\n        // @TODO: It origianlly returned the item although the docs say id.\n        // The code expects the item, so probably an error in the docs.\n        let ident;\n        // confirm the id to use based on the args type\n        if (isId(id)) {\n            ident = id;\n        }\n        else if (id && typeof id === \"object\") {\n            ident = id[this._idProp]; // look for the identifier field using ._idProp\n        }\n        // do the removing if the