           const itemField = item[field];\n            if (typeof itemField === \"number\" &&\n                (minField == null || itemField < minField)) {\n                min = item;\n                minField = itemField;\n            }\n        }\n        return min || null;\n    }\n    /**\n     * Find all distinct values of a specified field\n     * @param prop - The property name whose distinct values should be returned.\n     * @returns Unordered array containing all distinct values. Items without specified property are ignored.\n     */\n    distinct(prop) {\n        const data = this._data;\n        const itemIds = [...data.keys()];\n        const values = [];\n        let count = 0;\n        for (let i = 0, len = itemIds.length; i < len; i++) {\n            const id = itemIds[i];\n            const item = data.get(id);\n            const value = item[prop];\n            let exists = false;\n            for (let j = 0; j < count; j++) {\n                if (values[j] == value) {\n                    exists = true;\n                    break;\n                }\n            }\n            if (!exists && value !== undefined) {\n                values[count] = value;\n                count++;\n            }\n        }\n        return values;\n    }\n    /**\n     * Add a single item. Will fail when an item with the same id already exists.\n     * @param item - A new item to be added.\n     * @returns Added item's id. An id is generated when it is not present in the item.\n     */\n    _addItem(item) {\n        const fullItem = ensureFullItem(item, this._idProp);\n        const id = fullItem[this._idProp];\n        // check whether this id is already taken\n        if (this._data.has(id)) {\n            // item already exists\n            throw new Error(\"Cannot add item: item with id \" + id + \" already exists\");\n        }\n        this._data.set(id, fullItem);\n        ++this.length;\n        return id;\n    }\n    /**\n     * Update a single item: merge