iew will only contain items having a property group with value 1,\n * // and will only output fields id, text, and date.\n * var view = new vis.DataView(data, {\n * filter: function (item) {\n * return (item.group == 1);\n * },\n * fields: ['id', 'text', 'date']\n * });\n *\n * // subscribe to any change in the DataView\n * view.on('*', function (event, properties, senderId) {\n * console.log('event', event, properties);\n * });\n *\n * // update an item in the data set\n * data.update({id: 2, group: 1});\n *\n * // get all ids in the view\n * var ids = view.getIds();\n * console.log('ids', ids); // will output [1, 2]\n *\n * // get all items in the view\n * var items = view.get();\n * ```\n * @typeParam Item - Item type that may or may not have an id.\n * @typeParam IdProp - Name of the property that contains the id.\n */\nclass DataView extends DataSetPart {\n    /** @inheritDoc */\n    length = 0;\n    /** @inheritDoc */\n    get idProp() {\n        return this.getDataSet().idProp;\n    }\n    _listener;\n    _data; // constructor → setData\n    _ids = new Set(); // ids of the items currently in memory (just contains a boolean true)\n    _options;\n    /**\n     * Create a DataView.\n     * @param data - The instance containing data (directly or indirectly).\n     * @param options - Options to configure this data view.\n     */\n    constructor(data, options) {\n        super();\n        this._options = options || {};\n        this._listener = this._onEvent.bind(this);\n        this.setData(data);\n    }\n    // TODO: implement a function .config() to dynamically update things like configured filter\n    // and trigger changes accordingly\n    /**\n     * Set a data source for the view.\n     * @param data - The instance containing data (directly or indirectly).\n     * @remarks\n     * Note that when the data view is bound to a data set it won't be garbage\n     * collected unless the data set is too. Use `dataView.setData(null)` or\n     * `dataView.dispose()` to enable garbage collection before you lose the last\n     * reference.\n     */\n    setData(data) {\n        if (this._data) {\n            // unsubscribe from current dataset\n            if (this._data.off) {\n                this._data.off(\"*\", this._listener);\n            }\n            // trigger a remove of all items in memory\n            const ids = this._data.getIds({ filter: this._options.filter });\n            const items = this._data.get(ids);\n            this._ids.clear();\n            this.length = 0;\n            this._trigger(\"remove\", { items: ids, oldData: items });\n        }\n        if (data != null) {\n            this._data = data;\n            // trigger an add of all added items\n            const ids = this._data.getIds({ filter: this._options.filter });\n            for (let i = 0, len = ids.length; i < len; i++) {\n                const id = ids[i];\n                this._ids.add(id);\n            }\n            this.length = ids.length;\n            this._trigger(\"add\", { items: ids });\n        }\n        else {\n            this._data = new DataSet();\n        }\n        // subscribe to new dataset\n        if (this._data.on) {\n            this._data.on(\"*\", this._listener);\n        }\n    }\n    /**\n     * Refresh the DataView.\n     * Useful when the DataView has a filter function containing a variable parameter.\n     */\n    refresh() {\n        const ids = this._data.getIds({\n            filter: this._options.filter,\n        });\n        const oldIds = [...this._ids];\n        const newIds = {};\n        const addedIds = [];\n        const removedIds = [];\n        const removedItems = [];\n        // check for additions\n        for (let i = 0, len = ids.length; i < len; i++) {\n            const id = ids[i];\n            newIds[id] = true;\n            if (!this._ids.has(id)) {\n                addedIds.push(id);\n                this._ids.add(id);\n            }\n        }\n        // check for removals\n        for (let i = 0, len = oldIds.length; i < len; i++) {\n            const id = oldIds[i];\n            const item = this._data.get(id);\n            if (item == null) {\n                // @TODO: Investigate.\n                // Doesn't happen during tests or examples.\n                // Is it really impossible or could it eventually happen?\n                // How to handle it if it does? The types guarantee non-nullable items.\n                console.error(\"If you see this, report it please.\");\n            }\n            else if (!newIds[id]) {\n                removedIds.push(id);\n                removedItems.push(item);\n                this._ids.delete(id);\n            }\n        }\n        this.length += addedIds.length - removedIds.length;\n        // trigger events\n        if (addedIds.length) {\n            this._trigger(\"add\", { items: addedIds });\n        }\n        if (removedIds.length) {\n            this._trigger(\"remove\", { items: removedIds, oldData: removedItems });\n        }\n    }\n    /** @inheritDoc */\n    get(first, second) {\n        if (this._data == null) {\n            return null;\n        }\n        // parse the arguments\n        let ids = null;\n        let options;\n        if (isId(first) || Array.isArray(first)) {\n            ids = first;\n            options = second;\n        }\n        else {\n            options = first;\n        }\n        // extend the options with the default options and provided options\n        const viewOptions = Object.assign({}, this._options, options);\n        // create a combined filter method when needed\n        const thisFilter = this._options.filter;\n        const optionsFilter = options && options.filter;\n        if (thisFilter && optionsFilter) {\n            viewOptions.filter = (item) => {\n                return thisFilter(item) && optionsFilter(item);\n            };\n        }\n        if (ids == null) {\n            return this._data.get(viewOptions);\n        }\n      